"""
MCG Listing Page Generator
Normalizes raw scraped data and renders it into the full listing page HTML
using the MCG listing template (exact match to the 146 Northfleet design).
"""

import os
import re
import math
import logging
from typing import Optional

from jinja2 import Environment, FileSystemLoader, select_autoescape

logger = logging.getLogger(__name__)

TEMPLATE_DIR = os.path.join(os.path.dirname(__file__), "templates")

MAPS_EMBED_BASE = "https://maps.google.com/maps?q={address}&output=embed&z=15"

AGENT_DEFAULTS = {
    "name": os.getenv("AGENT_NAME", "Cameron Torabi"),
    "license": os.getenv("AGENT_LICENSE", "AR RE License #PB00056565"),
    "phone": os.getenv("AGENT_PHONE", "(858) 500-0222"),
    "email": os.getenv("AGENT_EMAIL", "info@masoncapitalgroup.com"),
    "photo_url": os.getenv("AGENT_PHOTO_URL", "data:image/jpeg;base64,"),
    "firm": "Mason Capital Group Real Estate Investment & Trust",
}

# ── Type classification ────────────────────────────────────────────────────────

_LAND_KEYWORDS = {"land", "lot", "acreage", "vacant land", "vacant lot", "farm", "ranch", "agricultural", "timberland"}
_RENTAL_KEYWORDS = {"apartment", "multi-family", "multifamily", "multi family", "triplex", "fourplex", "rental"}
_COMMERCIAL_KEYWORDS = {"office", "retail", "industrial", "warehouse", "flex", "storefront", "strip mall", "shopping center", "medical office", "r&d", "research"}
_INVESTMENT_KEYWORDS = {"investment", "income property", "nnn", "triple net", "net lease", "mixed use", "mixed-use"}
_DEVELOPMENT_KEYWORDS = {"development", "development opportunity", "redevelopment", "entitled", "pad site", "assemblage"}


def _classify_listing_type(raw: dict) -> str:
    prop_type = (raw.get("property_type") or "").lower().strip()
    for kw in _LAND_KEYWORDS:
        if kw in prop_type:
            return "land"
    for kw in _DEVELOPMENT_KEYWORDS:
        if kw in prop_type:
            return "development"
    for kw in _INVESTMENT_KEYWORDS:
        if kw in prop_type:
            return "investment"
    for kw in _COMMERCIAL_KEYWORDS:
        if kw in prop_type:
            return "commercial"
    for kw in _RENTAL_KEYWORDS:
        if kw in prop_type:
            return "rental"
    return raw.get("listing_type", "residential")


def normalize(raw: dict) -> dict:
    """
    Convert raw scraped data into a clean, fully-populated listing dict
    ready for the Jinja2 template.
    """
    # ── Helpers ────────────────────────────────────────────────────────────
    def _int(val, default=0):
        try:
            return int(val) if val is not None else default
        except (TypeError, ValueError):
            return default

    def _float(val, default=0.0):
        try:
            return float(val) if val is not None else default
        except (TypeError, ValueError):
            return default

    # ── Address ────────────────────────────────────────────────────────────
    street = raw.get("address_street", "").strip()
    city = raw.get("address_city", "").strip()
    state = raw.get("address_state", "").strip()
    zip_code = raw.get("address_zip", "").strip()
    full_address = f"{street}, {city}, {state} {zip_code}".strip(", ")

    # ── Listing type ───────────────────────────────────────────────────────
    listing_type = _classify_listing_type(raw)

    # Capability flags used by the template
    has_beds      = listing_type in ("residential", "rental")
    has_sqft      = listing_type in ("residential", "rental", "commercial", "investment")
    has_acreage   = listing_type in ("land", "development")
    has_loan_calc = listing_type in ("residential", "land")
    has_schools   = listing_type in ("residential", "rental")
    has_investment_metrics = listing_type in ("rental", "commercial", "investment")
    has_zoning    = listing_type in ("land", "commercial", "development")
    has_development_potential = listing_type in ("land", "development")

    # ── Status ────────────────────────────────────────────────────────────
    status = raw.get("status") or "Active"
    mls_number = raw.get("mls_number") or ""
    dom = raw.get("days_on_market") or 0
    dom_display = "New" if dom == 0 else str(dom)

    # ── Price ─────────────────────────────────────────────────────────────
    # Store as float so $1.25 lease rates survive; format per type
    price_float = _float(raw.get("price"))
    price_override = (raw.get("price_display") or "").strip()  # manual override wins

    if price_override:
        price_formatted = price_override
        price_label = raw.get("price_label", "List Price")
    elif listing_type == "commercial" and price_float < 100:
        # Lease rate per sqft per month/year
        lease_period = raw.get("lease_period", "MO").upper()
        price_formatted = f"${price_float:.2f}/SF/{lease_period}"
        price_label = "Lease Rate"
    elif listing_type == "rental" and price_float < 50000:
        price_formatted = f"${price_float:,.0f}/mo" if price_float else "Rent Upon Request"
        price_label = "Monthly Rent"
    elif price_float >= 1:
        price_formatted = f"${int(price_float):,}"
        price_label = raw.get("price_label", "List Price")
    else:
        price_formatted = "Price Upon Request"
        price_label = "List Price"

    price_raw = _int(price_float)

    # ── Key stats ──────────────────────────────────────────────────────────
    beds  = raw.get("beds") or 0
    baths = raw.get("baths") or 0
    sqft_raw = _int(raw.get("sqft"))
    sqft_formatted = f"{sqft_raw:,}" if sqft_raw else "—"
    price_per_sqft = _int(price_float / sqft_raw) if sqft_raw > 0 and price_float >= 1000 else _int(raw.get("price_per_sqft"))
    lot_sqft = _int(raw.get("lot_sqft"))
    lot_acres_raw = _float(raw.get("lot_acres")) or None
    if not lot_acres_raw and lot_sqft:
        lot_acres_raw = lot_sqft / 43560
    lot_acres_display = f"{lot_acres_raw:.2f}" if lot_acres_raw else (raw.get("lot_acres_display") or "—")

    # Land / development: total acreage may differ from lot_acres
    total_acres_raw = _float(raw.get("total_acres")) or lot_acres_raw or None
    total_acres_display = f"{total_acres_raw:.2f}" if total_acres_raw else lot_acres_display
    price_per_acre = _int(price_float / total_acres_raw) if total_acres_raw and price_float >= 1000 else _int(raw.get("price_per_acre"))

    year_built = raw.get("year_built")
    hoa_fee = raw.get("hoa_fee") or 0
    new_construction = raw.get("new_construction", year_built and year_built >= 2023)

    # ── Investment metrics ─────────────────────────────────────────────────
    units = _int(raw.get("units"))
    gross_rent_annual = _float(raw.get("gross_rent_annual")) or (
        _float(raw.get("gross_rent")) * 12 if raw.get("gross_rent") else 0
    )
    operating_expenses = _float(raw.get("operating_expenses")) or gross_rent_annual * 0.35
    noi = _float(raw.get("noi")) or (gross_rent_annual - operating_expenses)
    cap_rate = _float(raw.get("cap_rate")) or (noi / price_float * 100 if price_float > 0 else 0)
    price_per_unit = _int(price_float / units) if units > 0 else _int(raw.get("price_per_unit"))
    grm = round(price_float / gross_rent_annual, 2) if gross_rent_annual > 0 else _float(raw.get("grm"))
    lease_type = raw.get("lease_type") or ""  # NNN, Gross, MG, etc.
    occupancy_rate = _float(raw.get("occupancy_rate")) or 0
    avg_lease_term = raw.get("avg_lease_term") or ""
    noi_display = f"${int(noi):,}/yr" if noi else "—"
    cap_rate_display = f"{cap_rate:.2f}%" if cap_rate else "—"
    grm_display = f"{grm:.1f}x" if grm else "—"
    price_per_unit_display = f"${price_per_unit:,}" if price_per_unit else "—"
    gross_rent_display = f"${int(gross_rent_annual):,}/yr" if gross_rent_annual else "—"

    # ── Zoning / development ───────────────────────────────────────────────
    zoning = raw.get("zoning") or ""
    zoning_description = raw.get("zoning_description") or ""
    max_units = _int(raw.get("max_units"))
    far = _float(raw.get("far"))
    entitlements = raw.get("entitlements") or []
    utilities_available = raw.get("utilities_available") or []
    road_frontage = raw.get("road_frontage") or ""
    topography = raw.get("topography") or ""

    # ── Stats bar config ───────────────────────────────────────────────────
    # Each entry: {value, label} — template iterates this list
    stats_bar = _build_stats_bar(
        listing_type, beds, baths, sqft_formatted, price_per_sqft,
        total_acres_display, price_per_acre, units, cap_rate_display,
        noi_display, price_per_unit_display, zoning, raw
    )

    # ── Loan calculator ────────────────────────────────────────────────────
    loan_est = raw.get("loan_estimate", {})
    down_pct = loan_est.get("down_payment_pct", 20 if listing_type == "residential" else 35)
    down_amt = int(price_raw * down_pct / 100)
    loan_amt = price_raw - down_amt
    rate = loan_est.get("interest_rate", 6.89 if listing_type == "residential" else 7.5) / 100 / 12
    term = loan_est.get("loan_term", 30) * 12
    if rate > 0 and term > 0 and loan_amt > 0:
        pi = loan_amt * (rate * (1 + rate) ** term) / ((1 + rate) ** term - 1)
    else:
        pi = loan_est.get("principal_interest", 0)
    tax_annual = _int(raw.get("tax_annual")) or int(price_raw * 0.012)
    insurance_annual = int(price_raw * 0.004)
    monthly_tax = int(tax_annual / 12)
    monthly_ins = int(insurance_annual / 12)
    monthly_total = int(pi) + monthly_tax + monthly_ins

    # ── Photos ─────────────────────────────────────────────────────────────
    photos = raw.get("photos", [])
    seen = set()
    clean_photos = []
    for p in photos:
        url = p if isinstance(p, str) else (p.get("url") or p.get("href") or "")
        if url and url not in seen:
            seen.add(url)
            clean_photos.append(url)
        if len(clean_photos) >= 50:
            break

    # ── Map ────────────────────────────────────────────────────────────────
    map_query = full_address.replace(" ", "+")
    map_embed_url = MAPS_EMBED_BASE.format(address=map_query)

    # ── Description ────────────────────────────────────────────────────────
    desc_paragraphs = raw.get("description_paragraphs", [])
    if not desc_paragraphs:
        desc_raw = raw.get("description", "")
        if desc_raw:
            desc_paragraphs = [p.strip() for p in re.split(r"\n\n+", desc_raw) if p.strip()]
        if not desc_paragraphs:
            desc_paragraphs = ["Property details coming soon."]

    # ── Highlights ─────────────────────────────────────────────────────────
    highlights = raw.get("highlights", [])
    if not highlights:
        highlights = _build_default_highlights(
            raw, listing_type, beds, baths, sqft_formatted,
            lot_acres_display, total_acres_display, year_built,
            units, zoning, cap_rate_display
        )

    # ── Feature details ─────────────────────────────────────────────────────
    features = {
        "general": raw.get("features_general") or _build_general_features(
            raw, listing_type, mls_number, sqft_formatted, lot_acres_display,
            year_built, city, state, zip_code, hoa_fee, dom_display,
            zoning, units
        ),
        "interior": raw.get("features_interior") or [],
        "kitchen": raw.get("features_kitchen") or [],
        "exterior": raw.get("features_exterior") or [],
        "utilities": raw.get("features_utilities") or [],
        "location": raw.get("features_location") or [],
    }

    # ── Scores ─────────────────────────────────────────────────────────────
    walk    = raw.get("walk_score",    {"score": 15, "label": "Car-Dependent"})
    transit = raw.get("transit_score", {"score": 0,  "label": "Minimal Transit"})
    bike    = raw.get("bike_score",    {"score": 25, "label": "Bikeable"})

    # ── Schools ────────────────────────────────────────────────────────────
    schools = raw.get("schools", [])

    # ── Tax / history ──────────────────────────────────────────────────────
    tax_history  = raw.get("tax_history", [])
    comps        = raw.get("comparable_homes", [])
    prop_history = raw.get("property_history", [])

    # ── Location content ────────────────────────────────────────────────────
    location_tagline    = raw.get("location_tagline", f"The {city} Advantage")
    location_description = raw.get("location_description", "")
    location_cards      = raw.get("location_cards", [])

    # Curated Unsplash photo IDs: full-bleed, properly composed, content-matched.
